INSERT INTO texts (title, hanzi, pinyin, translation, hsk_level) VALUES
(
    'Знакомство',
    '你好!我叫王明。我是学生。我今年十八岁。我家有四个人:爸爸、妈妈、姐姐和我。我很高兴认识你。',
    'Nǐ hǎo! Wǒ jiào Wáng Míng. Wǒ shì xuésheng. Wǒ jīnnián shíbā suì. Wǒ jiā yǒu sì gè rén: bàba, māma, jiějie hé wǒ. Wǒ hěn gāoxìng rènshi nǐ.',
    'Привет! Меня зовут Ван Мин. Я студент. Мне в этом году восемнадцать лет. В моей семье четыре человека: папа, мама, старшая сестра и я. Я очень рад познакомиться с тобой.',
    1
),
(
    'Мой день',
    '我每天七点起床。早上我喝茶,吃米饭。然后我去学校。下午我回家,看电视。晚上我很累,九点睡觉。',
    'Wǒ měitiān qī diǎn qǐchuáng. Zǎoshang wǒ hē chá, chī mǐfàn. Ránhòu wǒ qù xuéxiào. Xiàwǔ wǒ huí jiā, kàn diànshì. Wǎnshang wǒ hěn lèi, jiǔ diǎn shuìjiào.',
    'Я каждый день встаю в семь часов. Утром я пью чай, ем рис. Потом я иду в школу. Днём я возвращаюсь домой, смотрю телевизор. Вечером я очень устал(а), ложусь спать в девять часов.',
    1
),
(
    'Выходные',
    '上个星期六,我和朋友一起去公园。天气非常好,不冷也不热。我们在公园里散步、聊天,还拍了很多照片。中午,我们在公园附近的饭店吃了午饭。那天我们都很开心。',
    'Shàng gè xīngqīliù, wǒ hé péngyou yìqǐ qù gōngyuán. Tiānqì fēicháng hǎo, bù lěng yě bú rè. Wǒmen zài gōngyuán lǐ sànbù, liáotiān, hái pāile hěn duō zhàopiàn. Zhōngwǔ, wǒmen zài gōngyuán fùjìn de fàndiàn chīle wǔfàn. Nà tiān wǒmen dōu hěn kāixīn.',
    'В прошлую субботу я вместе с другом пошёл в парк. Погода была очень хорошая, не холодно и не жарко. Мы гуляли по парку, болтали, и ещё сделали много фотографий. В обед мы поели в ресторане недалеко от парка. В тот день мы все были очень довольны.',
    2
),
(
    'Покупки',
    '昨天下午,妈妈带我去商店买衣服。商店里的衣服又漂亮又便宜。我买了一件红色的衣服,妈妈买了一双新鞋。我们一共花了三百块钱。回家的路上,我们还买了一些水果。',
    'Zuótiān xiàwǔ, māma dài wǒ qù shāngdiàn mǎi yīfu. Shāngdiàn lǐ de yīfu yòu piàoliang yòu piányi. Wǒ mǎile yí jiàn hóngsè de yīfu, māma mǎile yì shuāng xīn xié. Wǒmen yígòng huāle sānbǎi kuài qián. Huí jiā de lùshang, wǒmen hái mǎile yìxiē shuǐguǒ.',
    'Вчера днём мама взяла меня с собой в магазин купить одежду. Одежда в магазине была и красивая, и недорогая. Я купил(а) одну красную вещь, мама купила новую пару обуви. Мы вместе потратили триста юаней. По дороге домой мы ещё купили немного фруктов.',
    2
),
(
    'Моё хобби',
    '我从小就喜欢音乐。虽然我唱歌唱得不太好,但是我弹钢琴弹得不错。每天放学以后,我都会练习一个小时。我觉得音乐可以让人放松,忘记生活中的烦恼。我的梦想是有一天能开一场自己的音乐会。',
    'Wǒ cóngxiǎo jiù xǐhuan yīnyuè. Suīrán wǒ chànggē chàng de bú tài hǎo, dànshì wǒ tán gāngqín tán de búcuò. Měitiān fàngxué yǐhòu, wǒ dōu huì liànxí yí gè xiǎoshí. Wǒ juéde yīnyuè kěyǐ ràng rén fàngsōng, wàngjì shēnghuó zhōng de fánnǎo. Wǒ de mèngxiǎng shì yǒu yìtiān néng kāi yì chǎng zìjǐ de yīnyuèhuì.',
    'Я с детства люблю музыку. Хотя я не очень хорошо пою, зато неплохо играю на пианино. Каждый день после школы я занимаюсь по одному часу. Я думаю, музыка может расслабить человека, помочь забыть о заботах жизни. Моя мечта — однажды дать собственный концерт.',
    3
),
(
    'Весна в Пекине',
    '北京的春天比较短,只有一两个月。三月的时候,天气开始变暖和,树上长出了绿叶,公园里的花也开了。很多人喜欢在周末去公园看花、拍照。不过北京春天的风比较大,有时候还会下沙尘暴,所以出门的时候最好戴口罩。',
    'Běijīng de chūntiān bǐjiào duǎn, zhǐyǒu yì liǎng gè yuè. Sānyuè de shíhou, tiānqì kāishǐ biàn nuǎnhuo, shùshang zhǎngchūle lǜyè, gōngyuán lǐ de huā yě kāile. Hěn duō rén xǐhuan zài zhōumò qù gōngyuán kàn huā, pāizhào. Búguò Běijīng chūntiān de fēng bǐjiào dà, yǒu shíhou hái huì xià shāchénbào, suǒyǐ chūmén de shíhou zuìhǎo dài kǒuzhào.',
    'Весна в Пекине довольно короткая, всего один-два месяца. В марте погода начинает теплеть, на деревьях появляются зелёные листья, в парках расцветают цветы. Многие любят по выходным ходить в парк смотреть на цветы, фотографироваться. Однако весенний ветер в Пекине довольно сильный, иногда даже случаются песчаные бури, поэтому выходя из дома лучше надевать маску.',
    3
),
(
    'Плюсы и минусы онлайн-покупок',
    '随着互联网的发展,网络购物已经成为很多人生活中不可缺少的一部分。网购的好处很明显:方便、快捷,而且价格通常比实体店便宜。只要动动手指,就能买到全国甚至全世界的商品。然而,网购也存在一些问题,比如无法亲自体验商品质量,有时候还会遇到假货或者售后服务不好的情况。因此,消费者在网购时应该保持警惕,选择信誉好的商家。',
    'Suízhe hùliánwǎng de fāzhǎn, wǎngluò gòuwù yǐjīng chéngwéi hěn duō rén shēnghuó zhōng bùkě quēshǎo de yí bùfen. Wǎnggòu de hǎochù hěn míngxiǎn: fāngbiàn, kuàijié, érqiě jiàgé tōngcháng bǐ shítǐdiàn piányi. Zhǐyào dòngdong shǒuzhǐ, jiù néng mǎidào quánguó shènzhì quán shìjiè de shāngpǐn. Rán''ér, wǎnggòu yě cúnzài yìxiē wèntí, bǐrú wúfǎ qīnzì tǐyàn shāngpǐn zhìliàng, yǒu shíhou hái huì yùdào jiǎhuò huòzhě shòuhòu fúwù bù hǎo de qíngkuàng. Yīncǐ, xiāofèizhě zài wǎnggòu shí yīnggāi bǎochí jǐngtì, xuǎnzé xìnyù hǎo de shāngjiā.',
    'С развитием интернета онлайн-покупки уже стали неотъемлемой частью жизни многих людей. Преимущества онлайн-шопинга очевидны: удобно, быстро, а цены обычно ниже, чем в обычных магазинах. Достаточно пошевелить пальцами — и можно купить товары со всей страны и даже со всего мира. Однако у онлайн-покупок есть и проблемы: например, невозможно лично оценить качество товара, иногда можно столкнуться с подделками или плохим послепродажным обслуживанием. Поэтому потребителям следует сохранять бдительность при покупках онлайн и выбирать продавцов с хорошей репутацией.',
    4
),
(
    'Сила упорства',
    '古人说:"锲而不舍,金石可镂。"这句话的意思是,只要坚持不懈,即使是很坚硬的东西也能被雕刻出来。生活中,很多人一遇到困难就放弃,结果什么都做不成。其实,成功往往属于那些能够坚持到底的人。无论学习一门外语,还是培养一个新习惯,都需要时间和耐心。只要不轻易放弃,总有一天会看到进步。',
    'Gǔrén shuō: "Qiè ér bù shě, jīnshí kě lòu." Zhè jù huà de yìsi shì, zhǐyào jiānchí búxiè, jíshǐ shì hěn jiānyìng de dōngxi yě néng bèi diāokè chūlái. Shēnghuó zhōng, hěn duō rén yí yùdào kùnnan jiù fàngqì, jiéguǒ shénme dōu zuò bù chéng. Qíshí, chénggōng wǎngwǎng shǔyú nàxiē nénggòu jiānchí dàodǐ de rén. Wúlùn xuéxí yì mén wàiyǔ, háishi péiyǎng yí gè xīn xíguàn, dōu xūyào shíjiān hé nàixīn. Zhǐyào bù qīngyì fàngqì, zǒng yǒu yìtiān huì kàndào jìnbù.',
    'Древние говорили: «Если резать не переставая, даже металл и камень можно вырезать». Смысл этой фразы в том, что при упорной настойчивости даже самую твёрдую вещь можно вырезать. В жизни многие люди, столкнувшись с трудностью, сразу сдаются, и в итоге ничего не добиваются. На самом деле успех часто принадлежит тем, кто способен идти до конца. Изучаете ли вы иностранный язык или вырабатываете новую привычку — всё это требует времени и терпения. Если не сдаваться легко, однажды обязательно увидишь прогресс.',
    4
),
(
    'Расцвет экономики совместного использования',
    '近年来,共享经济在全球范围内迅速兴起,从共享单车、共享汽车到共享办公空间,几乎渗透到了生活的方方面面。共享经济的核心理念在于,通过互联网平台将闲置资源进行整合与再分配,从而提高资源利用率,降低消费成本。对消费者而言,这种模式无疑带来了极大的便利;然而,它同时也带来了监管、押金安全以及资源浪费等一系列亟待解决的问题。业内人士普遍认为,只有在鼓励创新与加强监管之间找到平衡,共享经济才能实现真正意义上的可持续发展。',
    'Jìnnián lái, gòngxiǎng jīngjì zài quánqiú fànwéi nèi xùnsù xīngqǐ, cóng gòngxiǎng dānchē, gòngxiǎng qìchē dào gòngxiǎng bàngōng kōngjiān, jīhū shèntòu dàole shēnghuó de fāngfāngmiànmiàn. Gòngxiǎng jīngjì de héxīn lǐniàn zàiyú, tōngguò hùliánwǎng píngtái jiāng xiánzhì zīyuán jìnxíng zhěnghé yǔ zài fēnpèi, cóng''ér tígāo zīyuán lìyòng lǜ, jiàngdī xiāofèi chéngběn. Duì xiāofèizhě ér yán, zhè zhǒng móshì wúyí dàiláile jídà de biànlì; rán''ér, tā tóngshí yě dàiláile jiānguǎn, yājīn ānquán yǐjí zīyuán làngfèi děng yìxìliè jítèi jiějué de wèntí. Yènèi rénshì pǔbiàn rènwéi, zhǐyǒu zài gǔlì chuàngxīn yǔ jiāqiáng jiānguǎn zhījiān zhǎodào pínghéng, gòngxiǎng jīngjì cáinéng shíxiàn zhēn yìyì shàng de kě chíxù fāzhǎn.',
    'В последние годы экономика совместного использования стремительно набирает силу во всём мире — от совместных велосипедов, автомобилей до общих офисных пространств, она проникла почти во все стороны жизни. Основная идея этой модели — через интернет-платформы объединять и перераспределять простаивающие ресурсы, тем самым повышая эффективность их использования и снижая расходы потребителей. Для потребителей эта модель, безусловно, приносит огромное удобство; однако одновременно она порождает ряд проблем, требующих решения — регулирование, безопасность залоговых депозитов и разбазаривание ресурсов. Специалисты отрасли в целом считают, что только найдя баланс между поощрением инноваций и усилением регулирования, экономика совместного использования сможет достичь подлинно устойчивого развития.',
    5
),
(
    'Смысл чтения',
    '古人云:"读万卷书,行万里路。"读书之于人生,犹如阳光雨露之于草木,看似无形,实则潜移默化地滋养着人的心灵。在信息爆炸的时代,碎片化阅读大行其道,人们习惯于快速浏览、囫囵吞枣,却鲜少静下心来细细品味一本书的深意。殊不知,唯有沉下心来阅读经典,才能真正开阔视野、提升思辨能力,进而在纷繁复杂的世界中保持一份清醒与从容。读书不仅是获取知识的途径,更是一场与自我对话、与历史对话的精神旅程。',
    'Gǔrén yún: "Dú wàn juàn shū, xíng wàn lǐ lù." Dúshū zhī yú rénshēng, yóurú yángguāng yǔlù zhī yú cǎomù, kànsì wúxíng, shízé qiányímòhuà de zīyǎngzhe rén de xīnlíng. Zài xìnxī bàozhà de shídài, suìpiànhuà yuèdú dàxíngqídào, rénmen xíguàn yú kuàisù liúlǎn, húlúntūnzǎo, què xiǎn shǎo jìng xiàxīn lái xìxì pǐnwèi yì běn shū de shēnyì. Shū bùzhī, wéiyǒu chén xiàxīn lái yuèdú jīngdiǎn, cáinéng zhēnzhèng kāikuò shìyě, tíshēng sībiàn nénglì, jìn''ér zài fēnfán fùzá de shìjiè zhōng bǎochí yí fèn qīngxǐng yǔ cóngróng. Dúshū bùjǐn shì huòqǔ zhīshi de tújìng, gèng shì yì chǎng yǔ zìwǒ duìhuà, yǔ lìshǐ duìhuà de jīngshén lǚchéng.',
    'Древние говорили: «Прочти десять тысяч свитков книг, пройди десять тысяч ли пути». Чтение для жизни человека подобно солнечному свету и росе для трав и деревьев — кажется незримым, но на самом деле незаметно взращивает душу человека. В эпоху информационного взрыва господствует фрагментарное чтение, люди привыкли быстро пролистывать, поглощать поверхностно, и редко успокаиваются, чтобы вдумчиво прочувствовать глубокий смысл книги. Между тем, лишь погрузившись всем сердцем в чтение классики, можно по-настоящему расширить кругозор, развить способность к критическому мышлению и тем самым сохранять ясность ума и спокойствие в сложном и запутанном мире. Чтение — это не только способ получения знаний, но и духовное путешествие — диалог с самим собой и с историей.',
    6
);
